  FeeSettings: 'FeeSettings',
  Receipt: 'Receipt',
  SchoolPaymentSettings: 'SchoolPaymentSettings',
  FeeAuditLog: 'FeeAuditLog',
  SmsTemplate: 'SmsTemplate',
  SmsWallet: 'SmsWallet',
  SmsWalletTransaction: 'SmsWalletTransaction',
  SmsLog: 'SmsLog',
  SmsTriggerConfig: 'SmsTriggerConfig',
  SmsSettings: 'SmsSettings',
  AiUsageLog: 'AiUsageLog',
  AiInsightCache: 'AiInsightCache',
  AiSettings: 'AiSettings',
  AiActionPolicy: 'AiActionPolicy',
  CronNotificationLog: 'CronNotificationLog',
  NotificationDailyLimit: 'NotificationDailyLimit',
  SchoolCarouselImage: 'SchoolCarouselImage',
  Competency: 'Competency',
  CompetencyAssessment: 'CompetencyAssessment',
  ActivityCategory: 'ActivityCategory',
  Activity: 'Activity',
  StudentActivityRecord: 'StudentActivityRecord',
  SELParameter: 'SELParameter',
  SELAssessment: 'SELAssessment',
  StudentReflection: 'StudentReflection',
  TeacherFeedback: 'TeacherFeedback',
